// 1. Grab the raw XML string exactly for this specific item
const rawXml = $input.item.json.data;

if (!rawXml || typeof rawXml !== 'string') {
  return { json: { trending_posts: [], error: "XML string missing." } };
}

const cleanData = [];

// 2. Split the massive text block into individual posts using the <entry> tag
const entries = rawXml.split('<entry>'); 
entries.shift(); // Remove the subreddit header text

for (const entry of entries) {

  // THE ABSOLUTE SAFEST EXTRACTOR: Uses character positions instead of splitting arrays
  const getTag = (startTag, endTag) => {
    const startIndex = entry.indexOf(startTag);
    if (startIndex === -1) return ""; // Start tag not found

    const contentStartIndex = startIndex + startTag.length;
    const endIndex = entry.indexOf(endTag, contentStartIndex);

    if (endIndex === -1) return ""; // End tag not found

    return entry.substring(contentStartIndex, endIndex).trim();
  };

  const title = getTag('<title>', '</title>') || "Untitled Post";
  const author = getTag('<name>', '</name>') || "Unknown User";

  // Link extraction
  let link = getTag('<link href="', '"');
  if (!link) link = getTag('href="', '"'); // Fallback if Reddit shifts the XML attributes around

  // Content extraction
  let content = getTag('<content type="html">', '</content>') || "";

  // 3. Scrub the Reddit HTML formatting clean
  content = content
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&amp;/g, '&')
    .replace(/<[^>]*>?/gm, ' ') // Deletes all HTML tags like <table>, <tr>
    .replace(/\s+/g, ' ')      // Condenses weird spacing
    .trim();

  if (!content) {
      content = "Image/Video only or no text body provided.";
  }

  // 4. Push the clean, structured data into our array
  cleanData.push({
    title: title,
    author: author,
    link: link,
    content_snippet: content.substring(0, 600) // Max 600 chars!
  });
}

// 5. Output perfectly structured JSON
return { 
    json: { 
        trending_posts: cleanData 
    } 
};

// 1. Grab all incoming items
const items = $input.all();

if (items.length === 0) {
  return [{ json: { error: "No data received." } }];
}

const item = items[0].json;

// 2. Navigate to the raw text from Gemini
const rawText = item.candidates[0].content.parts[0].text;

// 3. Parse the JSON string inside the text field
const parsed = JSON.parse(rawText);

// 4. Return headline and article_body as separate mappable fields
return [{
  json: {
    headline: parsed.headline,
    article_body: parsed.article_body
  }
}];
